import { type PropsWithChildren } from 'react';

import { ChoroplethLayerTooltip } from './ChoroplethLayerTooltip.js';
import type { ChoroplethLayerProps } from '../types/choropleth-layer.js';

/**
 * The `ChoroplethLayer` component allows users to display divided geographical
 * areas or regions that are coloured in relation to a given data. It provides an
 * easy way to visualize how a variable varies across a geographic area or show
 * the level of variability within a region.
 * @public
 */
export const ChoroplethLayer = <T extends Record<string, unknown>>(
  _: PropsWithChildren<ChoroplethLayerProps<T>>,
) => null;

ChoroplethLayer.Tooltip = ChoroplethLayerTooltip;
ChoroplethLayer['displayName'] = 'ChoroplethLayerSlot';
